import { useEffect } from "react";
import NavbarComponent from "../../components/Navbar";
import { useNavigate } from "react-router-dom";
import { StudentAuthApi } from "../../apis/student";
import { ParentAuthApi } from "../../apis/parent";


const RoomsPage = () => {
    // navigate
    const navigate = useNavigate()

    // get current admin ( hostel or parent or student)
    const admin = localStorage.getItem("admin")

    // use effect for login or not checking
    useEffect(() => {
        async function auth() {
            if (admin === "student") {
                const token = localStorage.getItem("studenttoken")
                if (token) {
                    const auth = await StudentAuthApi(token)
                    if (!auth || auth.status === "failed" || !auth.auth) {
                        navigate("/login")
                    }
                }
            } else {
                const token = localStorage.getItem("parenttoken")
                if (token) {
                    const auth = await ParentAuthApi(token)
                    if (!auth || auth.status === "failed" || !auth.auth) {
                        navigate("/login")
                    }
                }
            } 
        }
        auth()
    }, []);

    // return
    return (
        <>
            <NavbarComponent now={'home'} />
            <div className="w-auto min-h-screen px-3 pt-16 bg-[#1B263B]">
                <div className="w-full min-h-screen rounded-lg px-5 py-5 mt-3 bg-gray-400">
                    <div className="w-full p-5">
                        {/* Room list */}
                        <div className="grid grid-cols-1 md:grid-cols-1 lg:grid-cols-2 gap-5">
                            {[...Array(4)].map((_, index) => (
                                <div key={index} className="flex flex-row border p-4 rounded-lg shadow-md">
                                    <img
                                        src="https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcTpDm45kK65a-kzQ0gRaH7K78haHb8T9ySeiQ&s"
                                        alt="Example"
                                        className="rounded-md shadow-lg w-40 h-25"
                                    />
                                    <div className="ml-5">
                                        <h1 className="text-lg font-extrabold">
                                            Room No - 100 <span className="font-semibold">( Single )</span>
                                        </h1>
                                        <h1 className="text-md font-bold mt-1">Vacancy - 3</h1>
                                        <h1 className="text-md font-bold mt-1">
                                            Facilities - <span className="font-semibold">Laundry, WiFi</span>
                                        </h1>
                                        <h1 className="text-xl font-extrabold mt-1">₹4000</h1>
                                    </div>
                                </div>
                            ))}
                        </div>
                    </div>
                </div>
            </div>
        </>
    );
}

export default RoomsPage;
